Algorithm CFG-to-PDA(G = (V, T, P, S)):
 // Create PDA P = (Q, T, Γ, δ, q0, Z0, F)

 // States: {q} only
 // Start symbol: Z0 = $

 // For each production A → α:
 // Add transition δ(q, ε, A) = {(q, α)}

 // For each terminal a:
 // Add transition δ(q, a, a) = {(q, ε)}

 // Accept by empty stack

 // Example: S→aSb | ε
 // δ(q, ε, S) → {(q, aSb), (q, ε)}
 // δ(q, a, a) → {(q, ε)}

Algorithm CYK(w, G in CNF):
 n = length(w)
 Create table P[n+1][n+1]

 // Initialize diagonal: P[i][i] = {A | A → w[i] in G}
 For i = 1 to n:
 For each production A → a:
 If w[i] == a:
 Add A to P[i][i]

 // Fill table for longer substrings
 For length = 2 to n:
 For i = 1 to n-length+1:
 j = i + length - 1
 For split = i to j-1:
 For each production A → BC:
 If B in P[i][split] AND C in P[split+1][j]:
 Add A to P[i][j]

 // String accepted if S in P[1][n]
 Return S ∈ P[1][n]

// Example: w = "aabb", G: S→AB, A→a, B→b
// P[1][1] = {A}, P[2][2] = {}, P[3][3] = {B}, P[4][4] = {}
// P[1][2]: no split works → {}
// P[1][4]: Check splits → S added → ACCEPT
